"use client"

import { CopyButton } from "@/components/copy-button"
import { cn } from "@/lib/utils"

interface CodeSnippetProps {
  title?: string
  code: string
  language?: string
  className?: string
}

export function CodeSnippet({
  title,
  code,
  language = "tsx",
  className,
}: CodeSnippetProps) {
  if (!code) {
    return null
  }

  return (
    <figure data-rehype-pretty-code-figure="" className={cn("mt-0", className)}>
      {title ? (
        <figcaption
          className="text-code-foreground flex items-center gap-2 [&_svg]:size-4 [&_svg]:opacity-70"
          data-language={language}
          data-rehype-pretty-code-title=""
        >
          {title}
        </figcaption>
      ) : null}
      <CopyButton event="copy_component_code" value={code} />
      <div className="max-h-96 min-h-[350px] overflow-auto rounded-xl border border-border/60">
        <pre
          className="no-scrollbar min-w-0 overflow-x-auto px-4 py-3.5 outline-none !bg-transparent"
          data-language={language}
        >
          <code className="font-mono text-sm leading-relaxed">{code}</code>
        </pre>
      </div>
    </figure>
  )
}

